function calculateShipping(order: Order, user: User, config: ShippingConfig, promoCode?: string): number {
  let cost = 0;
  for (const item of order.items) {
    const weight = item.weight * item.quantity;
    if (weight > 50) {
      cost += weight * config.heavyRate;
      if (item.fragile) {
        cost += weight * 0.3;
      }
    } else if (weight > 20) {
      cost += weight * config.mediumRate;
    } else {
      cost += weight * config.lightRate;
    }
  }
  if (user.tier === 'gold') {
    cost *= 0.8;
  } else if (user.tier === 'silver') {
    cost *= 0.9;
  }
  if (promoCode === 'FREESHIP') {
    cost = 0;
  }
  return Math.max(cost, 0);
}
