public ResponseEntity<?> handleRequest(HttpServletRequest request) {
    String token = request.getHeader("Authorization");
    if (token != null) {
        if (token.startsWith("Bearer ")) {
            String jwt = token.substring(7);
            try {
                Claims claims = Jwts.parser().setSigningKey(secret).parseClaimsJws(jwt).getBody();
                if (claims.getExpiration().after(new Date())) {
                    String role = claims.get("role", String.class);
                    if (role != null) {
                        if (role.equals("admin") || role.equals("superadmin")) {
                            String action = request.getParameter("action");
                            if (action != null) {
                                if (action.equals("delete")) {
                                    String targetId = request.getParameter("id");
                                    if (targetId != null) {
                                        try {
                                            Long id = Long.parseLong(targetId);
                                            Optional<User> user = userRepo.findById(id);
                                            if (user.isPresent()) {
                                                userRepo.delete(user.get());
                                                auditLog.log(claims.getSubject(), "DELETE_USER", id);
                                                return ResponseEntity.ok(Map.of("deleted", id));
                                            } else {
                                                return ResponseEntity.status(404).body("User not found");
                                            }
                                        } catch (NumberFormatException e) {
                                            return ResponseEntity.badRequest().body("Invalid ID");
                                        }
                                    } else {
                                        return ResponseEntity.badRequest().body("Missing id");
                                    }
                                } else {
                                    return ResponseEntity.badRequest().body("Unknown action");
                                }
                            } else {
                                return ResponseEntity.badRequest().body("Missing action");
                            }
                        } else {
                            return ResponseEntity.status(403).body("Forbidden");
                        }
                    } else {
                        return ResponseEntity.status(403).body("No role");
                    }
                } else {
                    return ResponseEntity.status(401).body("Token expired");
                }
            } catch (JwtException e) {
                return ResponseEntity.status(401).body("Invalid token");
            }
        } else {
            return ResponseEntity.status(401).body("Bad auth format");
        }
    } else {
        return ResponseEntity.status(401).body("No auth header");
    }
}
