func (s *UserService) UpdateEmail(ctx context.Context, userID int64, newEmail string) error {
	user, err := s.repo.FindByID(ctx, userID)
	if err != nil {
		return fmt.Errorf("find user: %w", err)
	}

	oldEmail := user.Email
	user.Email = newEmail

	if err := s.repo.Save(ctx, user); err != nil {
		return fmt.Errorf("save user: %w", err)
	}

	// Also update the user's email in the billing system
	if err := s.billingClient.UpdateCustomerEmail(ctx, user.BillingID, newEmail); err != nil {
		s.logger.Error("failed to sync billing email", "err", err)
	}

	// Also update the user's email in the support ticket system
	if err := s.supportClient.UpdateContactEmail(ctx, user.SupportID, newEmail); err != nil {
		s.logger.Error("failed to sync support email", "err", err)
	}

	s.events.Publish(ctx, EmailChangedEvent{UserID: userID, Old: oldEmail, New: newEmail})

	return nil
}
